using System.Security.Claims;using AIFormationPlatform.Core.Entities;using AIFormationPlatform.Infrastructure.Data;using Microsoft.AspNetCore.Authentication;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.AspNetCore.Mvc.RazorPages;using Microsoft.EntityFrameworkCore;
namespace AIFormationPlatform.Web.Pages.Apprenant;
[Authorize(Roles="Apprenant")] public class FormationModel(ApplicationDbContext context):PageModel {public Formation Formation{get;private set;}=default!;public bool Inscrit{get;private set;} public async Task<IActionResult> OnGetAsync(int id){var f=await context.Formations.Include(x=>x.Modules).SingleOrDefaultAsync(x=>x.Id==id);if(f is null)return NotFound();Formation=f;Inscrit=await context.Inscriptions.AnyAsync(i=>i.FormationId==id&&i.ApprenantId==User.FindFirstValue(ClaimTypes.NameIdentifier));return Page();}public async Task<IActionResult> OnPostInscrireAsync(int id){var uid=User.FindFirstValue(ClaimTypes.NameIdentifier)!;if(!await context.Inscriptions.AnyAsync(i=>i.FormationId==id&&i.ApprenantId==uid)){context.Inscriptions.Add(new Inscription{FormationId=id,ApprenantId=uid});await context.SaveChangesAsync();TempData["Success"]="Vous êtes inscrit à cette formation.";}return RedirectToPage(new{id});}}
